Okay, let's address the requirement to prevent `fn()` from running again if the previous execution is still ongoing.

The current `time.Ticker` approach will fire at fixed intervals regardless of how long `fn()` takes. To achieve the desired behavior, you need a mechanism to track whether `fn` is currently executing.

Here are two common approaches:

**Method 1: Using `time.Timer` (Recommended for this scenario)**

Instead of a `Ticker` which fires periodically regardless, use a `Timer`. After `fn` completes, you reset the timer for the next interval. This ensures the interval starts *after* the previous execution finishes.

```go
// ---------------------------------------------------------------------------------------------------
// <copyright file="simple_scheduler.go" company="Omnissa, LLC.">
// Copyright © 2024 Omnissa, LLC. All rights reserved.
// This product is protected by copyright and intellectual property laws in the United States and other countries as well as by international treaties.
// Omnissa products may be covered by one or more patents listed at https://www.omnissa.com/omnissa-patent-information/
// </copyright>
// ---------------------------------------------------------------------------------------------------

package scheduler

import (
	"context"
	"log" // Or your preferred logger
	"sync/atomic"
	"time"
)

// simpleScheduler is an implementation of the Scheduler interface.
type simpleScheduler struct {
	cancel      context.CancelFunc
	cancelled   chan struct{}
	stopped     atomic.Bool // Use atomic bool for thread-safe access
	isRunning   atomic.Bool // Track if fn is currently running
}

// NewSimpleScheduler creates a new instance of simple scheduler.
func NewSimpleScheduler() Scheduler {
	s := &simpleScheduler{
		cancelled: make(chan struct{}),
	}
	s.stopped.Store(true) // Initialize stopped state
	return s
}

// IsStopped returns the current status of the scheduler.
// It returns true if the scheduler has been stopped, and false otherwise.
//
// Returns:
//   - bool: The stopped status of the scheduler.
func (s *simpleScheduler) IsStopped() bool {
	return s.stopped.Load()
}

// Start begins the scheduling process with the given function and interval.
// It ensures that the function `fn` is not executed again if the previous
// execution has not yet completed. The interval starts *after* the previous
// execution finishes.
//
// Parameters:
//   - ctx context.Context: The context for cancellation.
//   - fn func(): The function to be executed on schedule.
//   - interval time.Duration: The minimum duration between the end of one execution and the start of the next.
//
// The scheduler will continue to run until either Stop is called or the
// provided context is cancelled. If an immediate first run is desired,
// consider calling fn() once before starting the scheduler goroutine or
// initializing the timer with 0 duration initially.
func (s *simpleScheduler) Start(ctx context.Context, fn func(), interval time.Duration) {
    // Prevent starting if already running
	if !s.stopped.CompareAndSwap(true, false) {
        log.Println("Scheduler already started") // Or return an error
        return
    }

	// Reset cancelled channel for potential reuse if stopped and restarted
	s.cancelled = make(chan struct{})
	s.isRunning.Store(false) // Ensure isRunning is false initially

	var execCtx context.Context
	execCtx, s.cancel = context.WithCancel(ctx) // Use a cancellable context

	go func() {
		defer close(s.cancelled)
		defer s.stopped.Store(true) // Ensure stopped is true when goroutine exits

        // Use a timer, not a ticker
        timer := time.NewTimer(interval)
        defer timer.Stop() // Ensure timer is stopped when exiting

		log.Println("Scheduler started") // Optional logging

		for {
			select {
			case <-execCtx.Done(): // Context cancelled externally or by Stop()
				log.Println("Scheduler context cancelled, stopping.")
                // Attempt to drain the timer channel if Stop raced with a firing timer
                if !timer.Stop() {
					select {
					case <-timer.C: // Drain the channel
					default:
					}
				}
				return // Exit the goroutine

			case <-timer.C: // Timer fired
                // Check if already running (shouldn't happen with Timer logic, but belt-and-suspenders)
				if !s.isRunning.CompareAndSwap(false, true) {
					log.Println("Scheduler: fn still running, skipping this cycle (Timer logic error?)")
                    // This case *shouldn't* be hit with the Timer approach,
                    // as we only reset *after* fn completes.
                    // But if it were, we'd reset the timer immediately to try again later.
                    timer.Reset(interval)
					continue
				}

                // Run the function in a separate goroutine ONLY IF you want the *scheduling*
                // loop to remain responsive to cancellation during a long fn() execution.
                // If fn() is short or blocking the scheduler loop is acceptable, run it directly.
                // For this requirement (don't run again if busy), running directly is simpler.

                // --- Direct Execution (Simpler for this specific requirement) ---
                func() {
                    // Use defer to ensure isRunning is reset and timer is reset, even if fn panics
                    defer func() {
                        s.isRunning.Store(false)
                        // Reset the timer *after* fn finishes (or panics)
                        // Check context again *before* resetting to prevent reset after stop
                        select {
                        case <-execCtx.Done():
                           log.Println("Scheduler: Context done after fn, not resetting timer.")
                           // Timer will not be reset, loop will exit on next iteration via ctx.Done()
                        default:
                            timer.Reset(interval)
                            log.Println("Scheduler: fn finished, timer reset.")
                        }
                    }()
					log.Println("Scheduler: executing fn")
                    fn() // Execute the function
                }()
                // --- End Direct Execution ---
			}
		}
	}()
}


// Stop halts the scheduler's operations.
// It cancels the internal context and waits for the scheduler goroutine to finish.
// After calling Stop, IsStopped will return true.
//
// This method is idempotent.
func (s *simpleScheduler) Stop() {
	// Check if already stopped or never started
	if s.stopped.Load() {
        return
    }

	// Signal cancellation
	if s.cancel != null {
        log.Println("Scheduler: Stop requested.")
		s.cancel() // Signal the goroutine to stop

		// Wait for the goroutine to acknowledge cancellation and exit
		<-s.cancelled // Wait until the goroutine's defer close(s.cancelled) runs
        log.Println("Scheduler: Stopped.")
	}
    // s.stopped is set to true by the goroutine's defer statement
}

// Interface definition (assuming it exists elsewhere)
type Scheduler interface {
    Start(ctx context.Context, fn func(), interval time.Duration)
    Stop()
    IsStopped() bool
}
```

**Key Changes in Method 1:**

1.  **`time.Timer` instead of `time.Ticker`**: A timer fires once after a duration.
2.  **`timer.Reset(interval)`**: After `fn()` completes, we reset the timer to fire again after the *next* `interval`. This guarantees the delay starts *after* completion.
3.  **`isRunning` atomic flag**: While the timer logic inherently prevents overlap, adding an `atomic.Bool` (`isRunning`) can be a safeguard or useful if you adapt the logic later. It's used with `CompareAndSwap` for safe checking and setting. *(Self-correction: With the pure timer logic, `isRunning` isn't strictly necessary but added for clarity/robustness)*.
4.  **Context Check Before Reset**: Added a check `execCtx.Done()` *before* resetting the timer. This prevents resetting the timer if `Stop()` was called while `fn()` was running.
5.  **Stopping the Timer**: Added `defer timer.Stop()` and explicit draining in the `ctx.Done()` case, as recommended by `time.Timer` documentation for clean shutdown.
6.  **Atomic `stopped`**: Changed `stopped` to `atomic.Bool` for thread-safe reads in `IsStopped` and writes in `Start`/`Stop`/goroutine exit. Used `CompareAndSwap` in `Start` to prevent double starts.
7.  **Idempotent Stop**: Made `Stop` check `s.stopped` first.
8.  **Panic Safety**: Used `defer` within an anonymous function wrapper around the `fn()` call to ensure `s.isRunning.Store(false)` and `timer.Reset(interval)` (or context check) happen even if `fn` panics.
9.  **Logging**: Added basic logging for clarity.

---

**Method 2: Using a Mutex or Atomic Flag with Ticker (Skip if Busy)**

This method keeps the `Ticker` but uses a flag (like `sync.Mutex` or `atomic.Bool`) to check if `fn` is already running. If it is, the current tick is simply skipped. This means the execution might drift relative to the original schedule if `fn` takes longer than the interval.

```go
import (
	"context"
	"log"
	"sync"      // Or "sync/atomic"
	"time"
)

// simpleScheduler using Ticker + Mutex
type simpleSchedulerMutex struct {
	cancel    context.CancelFunc
	cancelled chan struct{}
	stopped   atomic.Bool
	mu        sync.Mutex // To protect access to fn execution state
}

func NewSimpleSchedulerMutex() Scheduler {
	s := &simpleSchedulerMutex{
		cancelled: make(chan struct{}),
	}
	s.stopped.Store(true)
	return s
}

func (s *simpleSchedulerMutex) IsStopped() bool {
	return s.stopped.Load()
}

// Start using Ticker + Mutex (Skips if busy)
func (s *simpleSchedulerMutex) Start(ctx context.Context, fn func(), interval time.Duration) {
	if !s.stopped.CompareAndSwap(true, false) {
        log.Println("Scheduler (Mutex): already started")
        return
    }

	s.cancelled = make(chan struct{})
	var execCtx context.Context
	execCtx, s.cancel = context.WithCancel(ctx)

	go func() {
		defer close(s.cancelled)
		defer s.stopped.Store(true)

		ticker := time.NewTicker(interval)
		defer ticker.Stop()

		log.Println("Scheduler (Mutex): started")

		for {
			select {
			case <-execCtx.Done():
				log.Println("Scheduler (Mutex): context cancelled, stopping.")
				return
			case <-ticker.C:
				// Try to acquire the lock, but don't block
				if s.mu.TryLock() {
					log.Println("Scheduler (Mutex): got lock, executing fn")
					// Use defer to guarantee unlock
					go func() { // Run in separate goroutine IF needed to prevent long fn blocking next tick check
						defer s.mu.Unlock()
						defer func() {
                            if r := recover(); r != nil {
                                log.Printf("Scheduler (Mutex): fn panicked: %v", r)
                                // Optionally handle panic further
                            }
                        }()
						fn()
                        log.Println("Scheduler (Mutex): fn finished, lock released")
					}()
                    // If fn is short/non-blocking, can run directly:
                    // func() {
                    //    defer s.mu.Unlock()
                    //    fn()
                    // }()

				} else {
					// If TryLock fails, fn is still running from a previous tick
					log.Println("Scheduler (Mutex): fn still running, skipping this tick.")
				}
			}
		}
	}()
}

// Stop for Mutex version
func (s *simpleSchedulerMutex) Stop() {
	if s.stopped.Load() {
		return
	}
	if s.cancel != nil {
        log.Println("Scheduler (Mutex): Stop requested.")
		s.cancel()
		<-s.cancelled
        log.Println("Scheduler (Mutex): Stopped.")
	}
}

// Interface definition (assuming it exists elsewhere)
// type Scheduler interface { ... }
```

**Comparison:**

*   **Method 1 (`time.Timer`)**: Ensures a *minimum* interval *between* executions (from end to start). If `fn` takes a long time, the next execution is delayed. This is usually the desired behavior when preventing overlap.
*   **Method 2 (`time.Ticker` + Mutex/Flag)**: Tries to execute on a fixed schedule. If `fn` is busy, the scheduled execution is *skipped* entirely. This might lead to fewer executions than expected if `fn` consistently takes longer than the interval. Use this if maintaining the *potential* start times is more important than guaranteeing execution after a delay.

For the requirement "avoiding calling fn() again if the previous execution has not completed yet", **Method 1 (using `time.Timer`) is generally the more appropriate and robust solution.**

